@Composable
fun AboutScreen() {

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(bottom = MaterialTheme.spacing.xxl)
    ) {
        item { AboutHeader() }
        item { AboutStats() }
        item { AboutDescription() }
        item { AboutHobbies() }
        item { AboutTechStack() }
        item { AboutApps() }
    }
}

@Composable
fun AboutHeader() {

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .height(MaterialTheme.sizes.imageLarge)
    ) {

        // Imagen fondo (tu foto)
        RMImage(
            source = RMImageSource.Url(PROFILE_IMAGE),
            modifier = Modifier.fillMaxSize(),
            contentScale = ContentScale.Crop
        )

        // Overlay oscuro pro
        Box(
            modifier = Modifier
                .matchParentSize()
                .background(
                    Brush.verticalGradient(
                        listOf(Color.Transparent, Color.Black)
                    )
                )
        )

        Column(
            modifier = Modifier
                .align(Alignment.BottomStart)
                .padding(MaterialTheme.spacing.lg)
        ) {

            RMTitleText(
                text = "Jesús Rico",
                color = Color.White
            )

            RMBodyText(
                text = "Android Engineer",
                color = Color.White.copy(alpha = 0.8f)
            )
        }
    }
}


@Composable
fun AboutStats() {

    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(MaterialTheme.spacing.lg),
        horizontalArrangement = Arrangement.SpaceEvenly
    ) {

        AboutStatItem(stringResource(R.string.years_old), stringResource(R.string.age_title))
        AboutStatItem(stringResource(R.string.years_exp), stringResource(R.string.years_exp_title))
        AboutStatItem(stringResource(R.string.specialist_title), stringResource(R.string.specialist))
    }
}

@Composable
fun AboutStatItem(value: String, label: String) {
    Column(horizontalAlignment = Alignment.CenterHorizontally) {

        RMTitleText(text = value)

        RMCaptionText(
            text = label,
            color = Color.Gray
        )
    }
}

@Composable
fun AboutDescription() {

    Column(modifier = Modifier.padding(horizontal = MaterialTheme.spacing.lg)) {

        RMTitleText(text = stringResource(R.string.about_me_title))

        Spacer(modifier = Modifier.height(MaterialTheme.spacing.sm))

        RMBodyText(
            text = stringResource(R.string.about_me_body),
        )
    }
}

@Composable
fun AboutHobbies() {

    Column(modifier = Modifier.padding(MaterialTheme.spacing.lg)) {

        RMTitleText(text = stringResource(R.string.hobbies_title))

        Spacer(modifier = Modifier.height(MaterialTheme.spacing.sm))

        Row(horizontalArrangement = Arrangement.spacedBy(MaterialTheme.spacing.sm)) {
            RMChip(stringResource(R.string.read_hobby))
            RMChip(stringResource(R.string.mma_hobby))
            RMChip(stringResource(R.string.mobile_hobby))
        }
    }
}

@Composable
fun RMChip(text: String) {
    Box(
        modifier = Modifier
            .clip(RoundedCornerShape(MaterialTheme.radius.circle))
            .background(Color.LightGray.copy(alpha = 0.3f))
            .padding(horizontal = MaterialTheme.spacing.md, vertical = MaterialTheme.spacing.xs)
    ) {
        RMCaptionText(text = text)
    }
}

@Composable
fun AboutTechStack() {

    val techs = listOf(
        stringResource(R.string.ts_kotlin),
        stringResource(R.string.ts_compose),
        stringResource(R.string.ts_mvvm),
        stringResource(R.string.ts_mvi),
        stringResource(R.string.ts_ca),
        stringResource(R.string.ts_modularization),
        stringResource(R.string.ts_ci_cd),
        stringResource(R.string.ts_kmp),
        stringResource(R.string.ts_swiftui),
        stringResource(R.string.ts_ia),
    )

    Column(modifier = Modifier.padding(MaterialTheme.spacing.lg)) {

        RMTitleText(text = stringResource(R.string.tech_stack_title))

        Spacer(modifier = Modifier.height(MaterialTheme.spacing.sm))

        FlowRow(
            horizontalArrangement = Arrangement.spacedBy(MaterialTheme.spacing.sm),
            verticalArrangement = Arrangement.spacedBy(MaterialTheme.spacing.sm)
        ) {
            techs.forEach {
                RMChip(it)
            }
        }
    }
}

@Composable
fun AboutApps() {

    Column(modifier = Modifier.padding(MaterialTheme.spacing.lg)) {

        RMTitleText(text = stringResource(R.string.collaborated_apps))

        Spacer(modifier = Modifier.height(MaterialTheme.spacing.lg))

        LazyRow (
            horizontalArrangement = Arrangement.spacedBy(MaterialTheme.spacing.lg)
        ) {
            item { AppLogo(STORI_APP) }
            item { AppLogo(BANREGIO_APP) }
            item { AppLogo(BANAMEX_APP) }
            item { AppLogo(VIVA_APP) }
            item { AppLogo(CINEPOLIS_APP) }
            item { AppLogo(PICKPAL_APP) }
            item { AppLogo(RECICLATELO_APP) }
        }
    }
}

@Composable
fun AppLogo(url: String) {
    RMCard(
        modifier = Modifier
            .size(MaterialTheme.sizes.profileCardHeight),
        contentPadding = PaddingValues(MaterialTheme.spacing.none),
    ) {
        RMImage(
            source = RMImageSource.Url(url),
            modifier = Modifier.fillMaxSize(),
            contentScale = ContentScale.Crop
        )
    }
}

